// PCA Ordination & Licensure Study — per-card MCQ overlay: wcf.
// Hand-authored multiple-choice for cards that can't auto-generate one, keyed
// by card id and merged into window.PCA_CARD_QUIZ (consumed by
// js/app/quiz.js cardQuiz()). Kept OUTSIDE the generated subject files so a
// builder re-run never wipes these. Each entry:
//   'card-id': { q?: 'sharper question override', choices: [4], answerIndex }
// Distractors must match the correct answer in length and grammatical shape
// (dev/validate.mjs giveaway check + manual discipline).
(function (global) {
  const Q = {
  'wcf-1-1': { q: 'According to WCF 1.1, why is Holy Scripture necessary, given the light of nature?', choices: ['Nature reveals enough of God to leave men without excuse, but not enough for salvation, so God committed his will to writing.', 'Nature reveals enough of God for salvation itself, but Scripture merely confirms it, so committing it to writing was not necessary.', 'Nature reveals nothing of God at all, but oral tradition sufficed for ages, so Scripture only formalized what was already known.', 'Nature reveals God’s will as fully as Scripture does, but the church still requires both alike, so neither is sufficient alone.'], answerIndex: 0 },
  'wcf-1-2': { q: 'According to WCF 1.2, what constitutes the canon of Holy Scripture?', choices: ['The 66 books of the Old and New Testaments plus the Apocrypha, all equally inspired for doctrine.', 'The 66 books of the Old and New Testaments, given by inspiration of God to be the rule of faith and life.', 'Only the New Testament writings, since the Old Testament was completed before Christ came.', 'Whatever books each local church chooses to receive as authoritative for its own use.'], answerIndex: 1 },
  'wcf-1-3': { q: 'According to WCF 1.3, what authority does the Apocrypha have in the church?', choices: ['Equal authority with the rest of Scripture, since the church has always read it alongside the canon.', 'Greater authority than most human writings, though slightly less than the inspired canon itself.', 'No more authority than other human writings, since it is not inspired and is no part of the canon.', 'Authority only over matters of church history, though not over doctrine or worship.'], answerIndex: 2 },
  'wcf-1-4': { q: 'According to WCF 1.4, upon what does the authority of Scripture ultimately depend?', choices: ['It rests wholly on God its own author, not on the testimony of any man or church, so it is received simply as his Word.', 'It rests on the church’s testimony and authority, not on any inward evidence at all, so councils alone can vouch for it.', 'It rests on the consensus of learned scholars, not on any word from God himself, so criticism alone establishes its truth.', 'It rests on its usefulness for morality and life, not on any question of divine origin, so results alone commend it.'], answerIndex: 0 },
  'wcf-1-5': { q: 'According to WCF 1.5, what gives believers full persuasion that Scripture is the Word of God?', choices: ['The inward work of the Holy Spirit bearing witness by and with the Word in their hearts.', 'The formal decree of a church council pronouncing the canon closed and authoritative.', 'The unbroken chain of manuscript transmission verified by careful textual scholars.', 'The absence of any errors detectable by ordinary historical and scientific investigation.'], answerIndex: 0 },
  'wcf-1-6': { q: 'According to WCF 1.6, how is the whole counsel of God concerning salvation made known?', choices: ['It is expressly set down in Scripture alone, so no doctrine may ever be reasoned out by inference.', 'It is expressly set down in Scripture or deduced from it by good and necessary consequence.', 'It is delivered partly by Scripture and partly by unwritten apostolic tradition preserved in the church.', 'It is discovered chiefly through private revelations granted to especially holy believers.'], answerIndex: 1 },
  'wcf-1-7': { q: 'According to WCF 1.7, how clear is Scripture concerning what must be known for salvation?', choices: ['It is so obscure that only ordained clergy trained in the original languages can rightly understand it.', 'It is equally plain in every part, so no passage is harder to understand than any other.', 'It is so clearly propounded that even the unlearned may attain a sufficient understanding by ordinary means.', 'It remains genuinely unclear until an infallible church interpreter authoritatively settles its meaning.'], answerIndex: 2 },
  'wcf-1-8': { q: 'According to WCF 1.8, why should Scripture be translated into the language of every people?', choices: ['Because the Hebrew and Greek texts have been lost and only translations now survive.', 'Because translations carry greater authority than the original Hebrew and Greek texts.', 'Because Latin alone had become unfit for public worship among the common people.', 'Because it was inspired in Hebrew and Greek but must reach all who do not know those original tongues.'], answerIndex: 3 },
  'wcf-1-9': { q: 'According to WCF 1.9, how is the true sense of a Scripture passage determined?', choices: ['By searching other clearer places of Scripture, since Scripture interprets itself infallibly.', 'By deferring to the earliest church fathers, since their readings settle every disputed sense.', 'By trusting the interpreter’s own experience, since spiritual intuition best fits each passage.', 'By allowing several equally valid senses at once, since no passage bears just one true meaning.'], answerIndex: 0 },
  'wcf-1-10': { q: 'According to WCF 1.10, who is the supreme judge of all religious controversies?', choices: ['The bishop of Rome, before whose judgments the whole church’s conscience must bow.', 'The Holy Spirit speaking in Scripture, before whom every human authority must yield.', 'A general council of the church, whose decrees no believer may ever question.', 'The private spirit of each believer, whose own conviction settles every dispute.'], answerIndex: 1 },
  'wcf-2-1': { q: 'According to WCF 2.1, what does the Confession affirm about the nature of God?', choices: ['There is but one living and true God, infinite in being and perfection, working all things for his own glory.', 'There are many true gods, each infinite in being within his own particular realm, working for his own glory.', 'God is a finite being, growing in knowledge and perfection as history unfolds, working toward eventual glory.', 'God is an impersonal force, without will, knowledge, or perfection, underlying and pervading all created things.'], answerIndex: 0 },
  'wcf-2-2': { q: 'According to WCF 2.2, how does God relate to his creatures?', choices: ['He depends on the worship of creatures to sustain his glory, needing their praise, though he still governs them.', 'He is limited in knowledge of contingent choices, learning as history unfolds, though he remains sovereign still.', 'He shares his sovereign rule with the highest angels, relying on their aid, though he alone is called God.', 'He is all-sufficient in himself, deriving no glory from creatures, though he is sovereign over them all.'], answerIndex: 3 },
  'wcf-2-3': { q: 'According to WCF 2.3, how does the Confession describe the Trinity?', choices: ['One God in three persons of one substance, power, and eternity — Father, Son, and Holy Ghost.', 'One God who appears successively as Father, Son, and Holy Ghost in three different modes.', 'Three separate gods united only in perfect agreement of purpose and will.', 'One supreme Father-God assisted by two lesser divine beings, the Son and the Spirit.'], answerIndex: 0 },
  'wcf-3-1': { q: 'According to WCF 3.1, how does God’s eternal decree relate to human freedom and sin?', choices: ['God ordained only the good and merely permits evil to occur outside his eternal decree entirely.', 'God ordained whatsoever comes to pass, yet without being the author of sin or destroying creatures’ liberty.', 'God ordained whatsoever comes to pass by directly causing sin as he causes every other event.', 'God foreordained nothing at all, leaving every outcome to purely undetermined human choice.'], answerIndex: 1 },
  'wcf-3-2': { q: 'According to WCF 3.2, did God decree things because he foresaw them as future?', choices: ['God decreed the elect to salvation because he foresaw that they would freely believe and persevere.', 'God’s decree and his foreknowledge are entirely unrelated, since foreknowledge plays no part in his eternal plan.', 'Though God foreknows all that might come to pass under any condition, he decreed nothing because he foresaw it.', 'God foreknows only what he himself has decreed to bring about, having no knowledge of unrealized possibilities.'], answerIndex: 2 },
  'wcf-3-3': { q: 'According to WCF 3.3, what has God decreed concerning men and angels?', choices: ['By his decree, all men and angels alike are predestinated to eternal life through Christ.', 'By his decree, only angels are predestinated, while every human destiny remains genuinely undetermined.', 'By his decree, men are predestinated to earthly blessing only, with eternal destiny left to their own choice.', 'By his decree, for the glory of his grace, some are predestinated to life and others foreordained to death.'], answerIndex: 3 },
  'wcf-3-4': { q: 'According to WCF 3.4, how definite is the number of the elect?', choices: ['So certain and definite that it cannot be either increased or diminished.', 'Approximate only, since God continually adds or subtracts from the elect as history unfolds.', 'Unknown even to God until the final judgment reveals who has believed.', 'Dependent on the church’s missionary success, which enlarges or shrinks the number of the elect.'], answerIndex: 0 },
  'wcf-3-5': { q: 'According to WCF 3.5, on what basis did God choose the elect?', choices: ['On the basis of foreseen faith, works, and perseverance that he knew the elect would display.', 'Out of his free grace and love alone, without any foreseen faith, works, or perseverance in them.', 'On the basis of foreseen zeal, virtue, and merit that marked some above the rest of mankind.', 'On the basis of future obedience, service, and worship he foresaw they would render him.'], answerIndex: 1 },
  'wcf-3-6': { q: 'According to WCF 3.6, who are redeemed by Christ, effectually called, and saved?', choices: ['All mankind without exception — all are redeemed by Christ, effectually called, and saved.', 'Every baptized member of the visible church — all are redeemed, called, and saved regardless of faith.', 'The elect only — none but the elect are redeemed by Christ, effectually called, and saved.', 'Only those who perform sufficient good works — they alone are redeemed, called, and saved by merit.'], answerIndex: 2 },
  'wcf-3-7': { q: 'According to WCF 3.7, what has God done with the rest of mankind, not elected to life?', choices: ['He elected them conditionally, awaiting their own future choice to accept or reject grace.', 'He determined to save them eventually, though by a later and lesser measure of grace.', 'He left their destiny entirely open, decreeing nothing at all concerning their end.', 'He was pleased to pass them by and ordain them to dishonor and wrath for their sin.'], answerIndex: 3 },
  'wcf-3-8': { q: 'According to WCF 3.8, how is the doctrine of predestination to be handled, and what should it produce?', choices: ['With special prudence and care, so those who heed it are assured of election from their effectual calling.', 'As a truth kept hidden from ordinary believers, lest it produce confusion or despair among them.', 'As a matter of pure speculation, with no bearing on Christian assurance or practical living.', 'As grounds for immediate certainty of one’s election apart from any evidence of effectual calling.'], answerIndex: 0 },
  'wcf-4-1': { q: 'According to WCF 4.1, how did God create the world?', choices: ['God gradually shaped the world out of pre-existing matter over vast, unspecified ages.', 'The triune God created the world and all things out of nothing in the space of six days, all very good.', 'God created the world through emanations from his own being rather than an act of will.', 'The Son alone created the world, apart from the will of the Father and the Spirit.'], answerIndex: 1 },
  'wcf-4-2': { q: 'According to WCF 4.2, in what condition did God create man?', choices: ['In a state already confirmed in righteousness, unable to sin, and needing no further probation.', 'As a purely physical being, without a reasonable soul, and incapable of any moral response.', 'In his own image, with the law written on their hearts and power to keep it, yet able to fall.', 'Already under the guilt of sin, corrupt from his first creation, and incapable of any obedience.'], answerIndex: 2 },
  'wcf-5-1': { q: 'According to WCF 5.1, how does God relate to all his creatures after creation?', choices: ['He created, upheld briefly, and then withdrew, leaving all things, great and small, to run by natural law.', 'He upholds, directs, and governs only the greatest matters, leaving ordinary things, day to day, to chance.', 'He upholds, directs, and governs the righteous only, abandoning the wicked, both great and small, to chance.', 'He upholds, directs, and governs all creatures and things, from the greatest to the least, by his providence.'], answerIndex: 3 },
  'wcf-5-2': { q: 'According to WCF 5.2, how do God’s decree and second causes relate in providence?', choices: ['All things fall out immutably by God’s decree, yet come to pass through second causes acting necessarily, freely, or contingently.', 'God’s decree operates only through necessary causes, so nothing in creation, however small, ever happens freely or by chance.', 'Second causes act wholly independently of God’s decree, controlling their own outcomes, freely, necessarily, or by chance alone.', 'God’s decree remains uncertain and incomplete, waiting on second causes, human choices, and chance to settle how things unfold.'], answerIndex: 0 },
  'wcf-5-3': { q: 'According to WCF 5.3, is God bound to work only through ordinary means in his providence?', choices: ['Yes — he bound himself at creation, forever, and without exception, to work only through natural means.', 'No — though he ordinarily uses means, he is free to work without, above, and against them at his pleasure.', 'Yes — miracles ceased, ended, and closed with the apostolic age, so he now works only through nature.', 'No — he never uses means at all, ordinary or extraordinary, working every effect immediately himself.'], answerIndex: 1 },
  'wcf-5-4': { q: 'According to WCF 5.4, how does God’s providence relate to sin?', choices: ['It has nothing to do with sin at all, since sin and its consequences lie entirely outside God’s providential government.', 'It directly causes sin in exactly the same determined way that it causes and produces every righteous act creatures perform.', 'It extends even to sin, not by bare permission but with a wise bounding of it, yet the sinfulness is from the creature alone.', 'It merely permits sin passively, without any real ordering, bounding, restraining, or governing purpose of it at all.'], answerIndex: 2 },
  'wcf-5-5': { q: 'According to WCF 5.5, why does God sometimes leave his own children to temptation for a season?', choices: ['To punish them for sins that even sincere and heartfelt repentance can never fully undo or forgive.', 'To determine, through their response, whether they were ever truly among his elect.', 'Because his providence has, in such moments, genuinely lost hold of their circumstances.', 'To chastise them for former sins, discover hidden corruption, humble them, and draw them to closer dependence on him.'], answerIndex: 3 },
  'wcf-5-6': { q: 'According to WCF 5.6, how does God, as a righteous judge, deal with wicked and ungodly men?', choices: ['He blinds and hardens them for their former sins, withholding grace and giving them over to their own lusts.', 'He extends to them exactly the same measure of softening grace he gives his elect people.', 'He forces them into sins they would not otherwise have any inclination to commit.', 'He withdraws his providence from them entirely, leaving their actions outside his governance.'], answerIndex: 0 },
  'wcf-5-7': { q: 'According to WCF 5.7, does God’s providence extend to his church in a special way?', choices: ['No — providence treats the church exactly as it treats every other institution in the world.', 'Yes — providence reaches all creatures generally, but cares for the church in a most special manner.', 'Yes — but only during the apostolic age, after which the church receives no special providential care.', 'No — the church, unlike the world, lies entirely outside the reach of God’s providence.'], answerIndex: 1 },
  'wcf-6-1': { q: 'According to WCF 6.1, how does the Confession describe God’s relation to Adam and Eve’s first sin?', choices: ['God directly forced and compelled Adam and Eve to sin, in his hidden will, so that grace might later be shown and displayed.', 'God was caught entirely by surprise by their sin, since it lay fully outside anything he had planned, known, or purposed.', 'God was pleased, according to his wise purpose, to permit their sin, having purposed to order it to his own glory.', 'God prevented the first sin, in his mercy, from having any lasting effect, consequence, or curse for their posterity.'], answerIndex: 2 },
  'wcf-6-2': { q: 'According to WCF 6.2, what happened to Adam and Eve as a result of their sin?', choices: ['They lost only a small measure of righteousness, remaining otherwise spiritually unharmed.', 'They fell under God’s judgment physically, though their souls remained untouched by sin.', 'They retained full communion with God, losing only their outward standing before other people.', 'They fell from original righteousness and communion with God, becoming dead in sin and wholly defiled.'], answerIndex: 3 },
  'wcf-6-3': { q: 'According to WCF 6.3, how does Adam’s sin affect his posterity?', choices: ['Its guilt is imputed and the same corrupted nature conveyed to all his posterity by ordinary generation.', 'It affects only Adam himself, since guilt can never be imputed from one person to another.', 'It affects posterity only through bad example and imitation, not through any imputed guilt or corrupted nature.', 'It affects only those descendants who personally approve of Adam’s original transgression.'], answerIndex: 0 },
  'wcf-6-4': { q: 'According to WCF 6.4, what does original corruption produce in fallen human nature?', choices: ['A nature still fully capable, quite unaided, of choosing spiritual good just as readily as evil.', 'Being utterly disabled and wholly inclined to all evil, it is the source from which all actual sins proceed.', 'Only outward bad habits, while the will itself remains entirely untouched, free, and unimpaired.', 'A mild inclination to evil easily overcome by ordinary human effort and willpower.'], answerIndex: 1 },
  'wcf-6-5': { q: 'According to WCF 6.5, does original corruption remain in believers after regeneration?', choices: ['No — regeneration entirely and immediately removes original corruption, leaving no remaining sin, guilt, or stain at all.', 'Yes — but because it is pardoned in Christ, and mortified in part, it can no longer be called sin in the regenerate.', 'Yes — it remains even in the regenerate, and though pardoned and mortified, it is still truly and properly sin.', 'No — original corruption, both before and after the fall, was only ever a legal fiction, absent from human nature.'], answerIndex: 2 },
  'wcf-6-6': { q: 'According to WCF 6.6, what does every sin, original and actual, bring upon the sinner?', choices: ['Only temporal consequences, since guilt before God attaches to actual sins alone.', 'No lasting guilt at all, provided the sinner later repents and turns from it.', 'A curse limited to physical death, without any further spiritual or eternal misery.', 'Guilt that binds him over to God’s wrath and curse, and to death with all its miseries.'], answerIndex: 3 },
  'wcf-7-1': { q: 'According to WCF 7.1, why did God condescend to relate to man by way of covenant?', choices: ['Because the distance between God and creature is so great that man could enjoy him only by God’s voluntary condescension.', 'Because man, by his own inherent and natural right, was fully entitled to fellowship with God as an equal partner.', 'Because angels had first negotiated and settled the covenant’s terms on behalf of the whole human race and its posterity.', 'Because covenant was simply one of several equally viable ways God might have chosen to relate to mankind at all.'], answerIndex: 0 },
  'wcf-7-2': { q: 'According to WCF 7.2, what were the terms of the first covenant God made with Adam?', choices: ['Life was promised freely to Adam apart from any condition of obedience whatsoever.', 'Life was promised to Adam and his posterity on condition of perfect, personal obedience.', 'Life was promised on condition of faith alone, apart from any requirement of obedience.', 'Life was promised only to Adam personally, with no bearing on his posterity at all.'], answerIndex: 1 },
  'wcf-7-3': { q: 'According to WCF 7.3, why did God make the covenant of grace?', choices: ['Because the covenant of works had proved unjust and impossible for fallen sinful man, so it was simply set aside and abolished.', 'Because Adam had, in fact and indeed, fulfilled the covenant of works himself, so grace simply confirmed and repeated it.', 'Because man made himself incapable of life by the covenant of works, so God freely offered life through faith in Christ.', 'Because the covenant of grace was always identical in its terms and conditions to the covenant of works given Adam.'], answerIndex: 2 },
  'wcf-7-4': { q: 'According to WCF 7.4, how is the covenant of grace set forth in Scripture?', choices: ['As a mere legal contract between two equal parties, negotiated without any testator or promised inheritance at all.', 'As a covenant carrying no reference whatsoever to Christ’s death or to any inheritance bequeathed by him.', 'As a testament that only takes legal effect after the testator himself has been raised again from the dead.', 'As a testament, with reference to the death of Christ the Testator and the everlasting inheritance bequeathed.'], answerIndex: 3 },
  'wcf-7-5': { q: 'According to WCF 7.5, how was the covenant of grace administered under the law?', choices: ['By promises, prophecies, sacrifices, circumcision, and other types foresignifying Christ, called the old testament.', 'By the very same sacraments of baptism, the Lord’s Supper, and public preaching later instituted under the gospel.', 'By no outward ordinances, sacraments, or ceremonies at all, since Old Testament saints related to God apart from means.', 'By civil laws, judicial statutes, and penalties alone, with no ceremonial types or sacrifices pointing to Christ.'], answerIndex: 0 },
  'wcf-7-6': { q: 'According to WCF 7.6, what is the relationship between the covenant administrations under the law and under the gospel?', choices: ['They are two entirely separate covenants of grace, unrelated in substance to one another.', 'There are not two covenants of grace but one and the same under various dispensations.', 'The gospel administration replaced the covenant of grace with a covenant of works reimposed.', 'The law administration offered salvation by works, while the gospel alone offers it by grace.'], answerIndex: 1 },
  'wcf-8-1': { q: 'According to WCF 8.1, what offices did God ordain the Lord Jesus to fulfill as Mediator?', choices: ['Prophet and King only, the priestly office having ceased with the Old Testament sacrifices.', 'A single undivided office of Judge, without any distinct prophetic, priestly, or kingly function.', 'Prophet, Priest, and King; Head and Savior of the church; Heir of all things and Judge of the world.', 'Priest and Judge only, since Christ’s prophetic and kingly work belongs to a future age.'], answerIndex: 2 },
  'wcf-8-2': { q: 'According to WCF 8.2, how are Christ’s divine and human natures united in his one person?', choices: ['His divine nature was converted, changed, and transformed into a human nature at the incarnation, becoming one new nature.', 'His human and divine natures were blended and mixed together into a single, new composite nature, entirely and completely.', 'His human nature was merely an outward appearance and disguise, temporarily assumed by his eternal, unchanging divine nature.', 'Two whole, perfect, distinct natures were inseparably joined in one person, without conversion, composition, or confusion.'], answerIndex: 3 },
  'wcf-8-3': { q: 'According to WCF 8.3, why was Christ’s human nature sanctified and anointed with the Spirit above measure?', choices: ['That he might be thoroughly furnished to execute the office of mediator and surety to which the Father called him.', 'Because his human nature, unlike his divine nature, needed to be cleansed from actual sin he had committed.', 'So that his human nature might eventually be absorbed entirely into his divine nature.', 'In order to qualify him merely as a moral example, apart from any mediatorial office.'], answerIndex: 0 },
  'wcf-8-4': { q: 'According to WCF 8.4, how did Christ execute the office of Mediator?', choices: ['He fulfilled the law, endured great torments, but did not die, since his obedience alone fully satisfied justice.', 'He perfectly fulfilled the law, endured torments, died, rose the third day, ascended, and intercedes, and will return to judge.', 'He died, rose bodily, ascended, and intercedes, but his mediatorial work fully ended at his own ascension into heaven.', 'He suffered, died, and was buried, but did not truly rise bodily, his resurrection being merely spiritual and inward.'], answerIndex: 1 },
  'wcf-8-5': { q: 'According to WCF 8.5, what did Christ’s obedience and sacrifice accomplish?', choices: ['It made salvation merely possible, satisfaction being completed only by each believer’s own works.', 'It satisfied divine justice partially, requiring further sacrifice to complete reconciliation.', 'It fully satisfied the Father’s justice and purchased reconciliation and an everlasting inheritance for the elect.', 'It purchased temporal blessing only, the eternal inheritance being secured by a separate means.'], answerIndex: 2 },
  'wcf-8-6': { q: 'According to WCF 8.6, were Old Testament believers saved by the virtue of Christ’s redemption?', choices: ['No — Old Testament believers were saved entirely by their own careful obedience to the ceremonial law and its rites.', 'No — salvation only became available to anyone at all after Christ’s incarnation had actually taken place in history.', 'Yes — but only to those Old Testament believers who kept the whole moral law perfectly, without a single failure.', 'Yes — its virtue and benefits were communicated to the elect in every age from the beginning, through promises and types.'], answerIndex: 3 },
  'wcf-8-7': { q: 'According to WCF 8.7, how does Christ act in the work of mediation?', choices: ['According to both natures, each doing what is proper to itself, though attributed to the person by reason of their union.', 'According to his divine nature alone, apart from any human action, his human nature contributing nothing at all.', 'According to his human nature alone, apart from any divine action, his divine nature remaining wholly inactive.', 'According to a single mixed nature, formed by blending, merging, and fusing the divine and human together.'], answerIndex: 0 },
  'wcf-8-8': { q: 'According to WCF 8.8, to whom does Christ certainly and effectually apply the redemption he purchased?', choices: ['To every human being without exception, since his purchase and its application are universal.', 'To all those for whom he purchased it, interceding for them and persuading them by his Spirit to believe.', 'Only to those who first apply it to themselves by an unaided act of their own will.', 'To none in particular, its application remaining genuinely uncertain until the last judgment.'], answerIndex: 1 },
  'wcf-9-1': { q: 'According to WCF 9.1, how did God endue man’s will?', choices: ['With natural liberty toward good alone, having no real capacity to ever choose or incline toward evil at all.', 'Without any real liberty at all, every human choice being strictly, mechanically, and fully determined beforehand.', 'With natural liberty, so that it is neither forced nor determined by any absolute necessity of nature to good or evil.', 'With liberty limited entirely to trivial matters, having no real bearing on moral good or evil whatsoever.'], answerIndex: 2 },
  'wcf-9-2': { q: 'According to WCF 9.2, what freedom did man have in the state of innocency?', choices: ['Freedom to do good only, in a fixed and settled way, having been created already incapable of falling into sin.', 'No real freedom to do good at all, being inclined toward evil, weakness, and folly even before the fall.', 'Freedom equal to that of the glorified saints in heaven, confirmed and secure, unable ever to sin or fall.', 'Freedom and power to will and do what was good and pleasing to God, yet mutably, so he could fall.'], answerIndex: 3 },
  'wcf-9-3': { q: 'According to WCF 9.3, what ability does fallen man have toward spiritual good?', choices: ['He wholly lost all ability of will to any spiritual good accompanying salvation, being dead in sin.', 'He retains full ability to convert himself to God by the exercise of his own natural will.', 'He retains a partial ability, enough to prepare himself for saving grace without divine aid.', 'He retains ability toward spiritual good equal to what he had before the fall.'], answerIndex: 0 },
  'wcf-9-4': { q: 'According to WCF 9.4, how is a sinner’s will freed to will and do what is spiritually good?', choices: ['The sinner freely wills his own conversion first, unaided and alone, and grace merely assists what he began.', 'God converts him, freeing him from bondage to sin and enabling him by grace alone, though imperfectly.', 'Conversion perfects the will at once, fully and finally, so that it wills only what is good from then on.', 'Conversion changes only outward behavior and habits, gradually, leaving the will’s inner bondage untouched.'], answerIndex: 1 },
  'wcf-9-5': { q: 'According to WCF 9.5, when is the human will made perfectly and immutably free to good alone?', choices: ['Already at effectual calling, since regeneration itself makes the will immutably free to good.', 'Never in this life or the next, since even glorified saints retain some capacity to sin.', 'Only in the state of glory, when the will is made perfectly and immutably free to good alone.', 'Already in the state of innocency, before the first sin corrupted Adam’s will.'], answerIndex: 2 },
  'wcf-10-1': { q: 'According to WCF 10.1, whom does God effectually call, and how?', choices: ['All mankind, without any distinction at all, since effectual calling is offered equally to elect and reprobate.', 'Only those who first prepare themselves, wholly on their own, by their own unaided efforts toward righteousness.', 'Only those born within the visible church, by heritage alone, regardless of any inward renewal of the will.', 'All and only those predestined to life, in his appointed time, by renewing their wills so they come to Christ freely.'], answerIndex: 3 },
  'wcf-10-2': { q: 'According to WCF 10.2, is effectual calling grounded in anything foreseen in man?', choices: ['No — it is of God’s free and special grace alone, man being passive until quickened by the Spirit.', 'Yes — it is grounded in faith and repentance, which God foresees the person will one day exercise.', 'Yes — it is grounded in good works, which God foresees the person will perform after being called.', 'No — but man, before the Spirit quickens him, actively initiates it wholly by his own effort.'], answerIndex: 0 },
  'wcf-10-3': { q: 'According to WCF 10.3, how are elect infants who die in infancy saved?', choices: ['They are saved automatically by their baptism alone, apart from any regenerating, renewing work of the Spirit.', 'They are regenerated and saved by Christ through the Spirit, who works when, where, and how he pleases.', 'They cannot be saved at all, in any case, since they are incapable of the outward call by the Word.', 'They are saved only if their parents, of their own accord, professed faith and formally dedicated them.'], answerIndex: 1 },
  'wcf-10-4': { q: 'According to WCF 10.4, can those who are outwardly called but not elect be saved?', choices: ['Yes — anyone outwardly called, in any nation, who diligently lives by the light of nature can be saved.', 'Yes — the outward call itself, apart from election entirely, is fully sufficient to bring anyone to salvation.', 'No — though they may receive some common operations of the Spirit, they never truly come to Christ and cannot be saved.', 'No — but only because such persons, through no fault of their own, were never outwardly called by the Word at all.'], answerIndex: 2 },
  'wcf-11-1': { q: 'According to WCF 11.1, how does God justify those he effectually calls?', choices: ['By infusing righteousness into them, so that they become inherently righteous in themselves.', 'By accepting their own good works as sufficient grounds for pardon and acceptance.', 'By imputing their own future faith and obedience rather than the obedience of Christ.', 'Not by infusing righteousness but by pardoning sin and imputing Christ’s obedience, received by faith alone.'], answerIndex: 3 },
  'wcf-11-2': { q: 'According to WCF 11.2, is the faith that justifies ever alone in the person justified?', choices: ['No — though faith alone is the instrument of justification, it is never alone but works by love.', 'Yes — true justifying faith exists entirely apart from any other grace or fruit of obedience.', 'No — faith is not the instrument of justification at all, but only one work among many.', 'Yes — justifying faith and good works are two separate instruments, either sufficient alone.'], answerIndex: 0 },
  'wcf-11-3': { q: 'According to WCF 11.3, why is the justification of sinners an act of God’s free grace?', choices: ['Because God simply overlooks and forgives sin, without any satisfaction of his own justice being required.', 'Because Christ’s satisfaction was freely accepted in the sinner’s stead, so grace and justice are both glorified.', 'Because the sinner’s own repentance and sorrow supplies whatever Christ’s satisfaction still leaves lacking.', 'Because Christ’s satisfaction, once made, obliges God to justify absolutely everyone without any exception.'], answerIndex: 1 },
  'wcf-11-4': { q: 'According to WCF 11.4, when are the elect actually justified?', choices: ['From all eternity, so that the elect were never, even before faith, in a state of condemnation.', 'Only at the final judgment, when their whole life of works is finally weighed.', 'Not until the Holy Spirit in due time actually applies Christ to them, though God decreed it from eternity.', 'At their physical birth, apart from any later application of Christ by the Spirit.'], answerIndex: 2 },
  'wcf-11-5': { q: 'According to WCF 11.5, can a justified believer ever fall from the state of justification?', choices: ['Yes — any deliberate sin, however small, immediately and completely forfeits their justified standing.', 'Yes — justification, like any wage, must be earned afresh through continual repentance and obedience.', 'No — because after justification, a believer no longer experiences God’s fatherly displeasure over sin.', 'No — they can never fall from justification, though by sin they may fall under God’s fatherly displeasure.'], answerIndex: 3 },
  'wcf-11-6': { q: 'According to WCF 11.6, how does the justification of believers under the Old Testament compare to that of the New?', choices: ['It was, in all respects, one and the same as the justification of believers under the New Testament.', 'It rested on obedience to the ceremonial law, not on Christ’s righteousness, imputed through faith alone.', 'It was a lesser, provisional justification, later replaced by the fuller justification under the gospel.', 'It applied only to the patriarchs, not to ordinary believers, living under the Mosaic covenant and law.'], answerIndex: 0 },
    'wcf-12-1': { q: 'According to WCF 12.1, what does the grace of adoption grant to the justified?', choices: ['A temporary status as God’s children — his name, his Spirit, access to grace, yet revocable for grievous sin.', 'The number and privileges of children of God — his name, his Spirit, access to grace, and never being cast off.', 'Only the outward name of sonship — no true Spirit, no real access to grace, and no promise of never being cast off.', 'Full adoption withheld until glory — no name, no Spirit, no access to grace enjoyed in this present life.'], answerIndex: 1 },
    'wcf-13-1': { q: 'According to WCF 13.1, what happens in the sanctification of the effectually called and regenerate?', choices: ['The dominion of sin is instantly and entirely eradicated at once, leaving no remaining lusts to be weakened.', 'The believer’s standing before God is changed, while his inward corruption, sadly, remains wholly untouched.', 'The dominion of sin is destroyed, its lusts more and more weakened, and the graces of the Spirit are quickened toward holiness.', 'Sin’s dominion actually increases for a season, unchecked, before the Spirit finally subdues it at death.'], answerIndex: 2 },
    'wcf-13-2': { q: 'According to WCF 13.2, is sanctification perfect in this life?', choices: ['Yes — sanctification is entirely, completely, and permanently finished the moment someone is effectually called.', 'No — sanctification touches only outward behavior and habits, never reaching the whole man at all.', 'Yes — though imperfect at first, it becomes fully complete for every believer well before death.', 'No — it is throughout the whole man, yet imperfect, with remnants of corruption causing a continual war within.'], answerIndex: 3 },
  'wcf-13-3': { q: 'According to WCF 13.3, who prevails in the ongoing war between the flesh and the Spirit in believers?', choices: ['The regenerate part overcomes through Christ’s sanctifying Spirit, so the saints grow in grace toward holiness.', 'The flesh ultimately prevails in every believer, so true holiness is never actually attained.', 'Neither side prevails, the two remaining in permanent, unresolved balance throughout life.', 'The outcome depends entirely on the believer’s own strength, without any aid of the Spirit.'], answerIndex: 0 },
    'wcf-14-1': { q: 'According to WCF 14.1, how is the grace of saving faith ordinarily wrought and increased?', choices: ['It is generated entirely by the believer’s own reasoning and effort, apart from any work of the Spirit.', 'It is the work of Christ’s Spirit, ordinarily wrought by the ministry of the Word and increased by Word, sacraments, and prayer.', 'It is wrought once for all time at baptism, quietly and completely, requiring no further increase by any means.', 'It is a natural human capacity present in everyone from birth, needing no special work of the Spirit at all.'], answerIndex: 1 },
    'wcf-14-2': { q: 'According to WCF 14.2, what are the principal acts of saving faith?', choices: ['Performing good works, penance, and almsgiving sufficient to merit acceptance before God’s judgment seat.', 'Assenting intellectually to true doctrine, without personal trust, love, or reliance on Christ himself.', 'Accepting, receiving, and resting on Christ alone for justification, sanctification, and eternal life.', 'Feeling a strong emotional confidence, apart from resting on Christ’s person, work, or promises.'], answerIndex: 2 },
  'wcf-14-3': { q: 'According to WCF 14.3, does saving faith differ in degrees among believers?', choices: ['No — every true believer possesses exactly the same measure of faith from the moment of conversion.', 'Yes — but once weakened by assault, faith can never again be strengthened or restored.', 'No — saving faith, being a gift, admits no growth or increase throughout the Christian life.', 'Yes — it may be weak or strong, often assailed and weakened, yet it gains the victory and grows toward full assurance.'], answerIndex: 3 },
  'wcf-15-1': { q: 'According to WCF 15.1, how is repentance unto life to be preached?', choices: ['As an evangelical grace, to be preached by every minister of the gospel as well as faith in Christ.', 'As a legal requirement belonging only to those still under the covenant of works.', 'As an optional practice, useful for some believers but not required to be preached to all.', 'As a work that must precede and merit the gift of saving faith in Christ.'], answerIndex: 0 },
    'wcf-15-2': { q: 'According to WCF 15.2, what does true repentance involve?', choices: ['Merely fearing the temporal punishments, losses, and shame that sin may bring upon oneself.', 'Seeing the danger and filthiness of sin, and grasping God’s mercy, so grieving for and turning from all sin to God.', 'Feeling passing regret over sin’s consequences, without any actual turning away from the sin itself.', 'Resolving firmly never to sin again, by sheer willpower, apart from any grasp of God’s mercy.'], answerIndex: 1 },
    'wcf-15-3': { q: 'According to WCF 15.3, is repentance any satisfaction for sin?', choices: ['Yes — repentance itself, though sincere, fully satisfies divine justice, making Christ’s satisfaction needless.', 'No — and it is not truly necessary at all, since pardon may be freely and fully had without repentance.', 'No — it is not to be rested in as any satisfaction for sin, yet it is so necessary that none may expect pardon without it.', 'Yes — repentance and Christ’s satisfaction, taken together, jointly pay the whole debt owed for every sin.'], answerIndex: 2 },
    'wcf-15-4': { q: 'According to WCF 15.4, is any sin too great to be pardoned in one who truly repents?', choices: ['Yes — some sins are so grievous that even true and sincere repentance cannot secure their pardon.', 'No — because, in truth, no single sin at all truly deserves eternal damnation before a holy God.', 'Yes — but only sins committed after baptism itself can ever place a person beyond all pardon.', 'No — no sin is so small it does not deserve damnation, yet none is so great it can damn those who truly repent.'], answerIndex: 3 },
  'wcf-15-5': { q: 'According to WCF 15.5, is a general repentance sufficient for the Christian?', choices: ['No — it is every man’s duty to endeavor to repent of his particular sins, particularly.', 'Yes — a single general repentance at conversion suffices for the whole of a believer’s life.', 'No — repentance must be general only, since attending to particular sins breeds needless scrupulosity.', 'Yes — particular sins need not be repented of once a person has come to saving faith.'], answerIndex: 0 },
  'wcf-15-6': { q: 'According to WCF 15.6, what is owed to a brother or the church who has been scandalized by one’s sin?', choices: ['Nothing further than private confession to God, since sin against others need not be confessed to them.', 'A declaration of repentance by private or public confession, upon which the offended are to be reconciled in love.', 'Permanent exclusion from fellowship, since scandal can never be repaired by confession alone.', 'A formal civil penalty imposed by the magistrate before the church may receive the offender back.'], answerIndex: 1 },
    'wcf-16-1': { q: 'According to WCF 16.1, what qualifies as a truly good work?', choices: ['Whatever a person sincerely intends for good, quite regardless of any warrant in God’s own Word.', 'Whatever the church’s long tradition has approved, even without explicit warrant in Scripture itself.', 'Only what God has commanded in his Word, not what men devise out of blind zeal or good intention without warrant.', 'Whatever produces beneficial results for society, whether or not God has ever commanded it at all.'], answerIndex: 2 },
  'wcf-16-2': { q: 'According to WCF 16.2, what do good works done in obedience to God’s commandments evidence?', choices: ['They are the very ground of justification, the cause rather than the fruit of a believer’s standing.', 'They are of no real evidential value, since even unbelievers can perform outwardly identical deeds.', 'They evidence only outward respectability, having no connection to inward faith at all.', 'They are the fruits and evidences of a true and lively faith, by which believers glorify God and edify others.'], answerIndex: 3 },
  'wcf-16-3': { q: 'According to WCF 16.3, from where does believers’ ability to do good works come?', choices: ['Wholly from the Spirit of Christ, who gives an actual influence beyond the graces already received.', 'Wholly from the believer’s own natural strength, renewed but essentially self-sufficient.', 'Partly from the Spirit and partly from human merit accumulated through habitual practice.', 'From the Spirit only at conversion, after which believers act entirely by their own unaided will.'], answerIndex: 0 },
  'wcf-16-4': { q: 'According to WCF 16.4, can believers in this life do more good works than God requires?', choices: ['Yes — the most devoted believers can perform works of supererogation beyond what God requires.', 'No — even those who attain the greatest obedience possible still fall short of much they are bound to do.', 'Yes — perfect obedience is fully attainable in this life by those who diligently pursue it.', 'No — because in this life believers are not bound to any obedience whatsoever.'], answerIndex: 1 },
    'wcf-16-5': { q: 'According to WCF 16.5, can believers merit pardon or eternal life by their good works?', choices: ['Yes — good works, once someone is regenerate, fully and completely merit both pardon and eternal life.', 'Yes — though unable to merit pardon at all, believers can still merit eternal life by works in the Spirit.', 'No — given the disproportion to future glory, we are unprofitable servants and our works cannot endure God’s judgment.', 'No — because believers, once truly and fully justified, no longer need to perform any good works whatsoever.'], answerIndex: 2 },
    'wcf-16-6': { q: 'According to WCF 16.6, how are the imperfect good works of believers accepted by God?', choices: ['They are accepted only once they have become entirely, perfectly, and finally free from every imperfection.', 'They are rejected outright, since anything at all imperfect, however small it may be, cannot please a holy God.', 'They are accepted on their own inherent merit, entirely apart from the believer’s standing in Christ himself.', 'Because their persons are accepted through Christ, God is pleased to accept and reward what is sincere despite its weaknesses.'], answerIndex: 3 },
    'wcf-16-7': { q: 'According to WCF 16.7, can works done by unregenerate men please God?', choices: ['No — though commanded and useful, they are sinful and cannot please God, yet neglecting them is more sinful still.', 'Yes — works done by unregenerate men please God, in every way, equally with the works of true believers.', 'No — and such works are of no real use to anyone at all, in any case, so neglecting them is no sin.', 'Yes — provided the unregenerate person sincerely, earnestly, and truly intends to please God by them.'], answerIndex: 0 },
    'wcf-17-1': { q: 'According to WCF 17.1, can those truly accepted in Christ totally or finally fall from grace?', choices: ['Yes — even true believers may totally, finally, and eternally fall away and be lost in the end.', 'No — they can neither totally nor finally fall from the state of grace but shall certainly persevere to the end.', 'Yes — believers may finally fall away, though never totally, at some point within this present life.', 'No — but only because God, in his mercy, prevents them from ever falling into serious sin at all.'], answerIndex: 1 },
    'wcf-17-2': { q: 'According to WCF 17.2, on what does the certainty of the saints’ perseverance depend?', choices: ['The believer’s own unaided will, strength, and resolve, which by itself secures perseverance to the end.', 'The strength, depth, and constancy of the believer’s feelings, which alone guarantee final perseverance.', 'The immutability of election, Christ’s merit and intercession, the abiding Spirit, and the nature of the covenant of grace.', 'The frequency, regularity, and outward visibility of church attendance maintained faithfully by the believer.'], answerIndex: 2 },
    'wcf-17-3': { q: 'According to WCF 17.3, can believers, notwithstanding their perseverance, fall into grievous sins for a time?', choices: ['No — true perseverance means believers never fall into any grievous sin at any point in their whole life.', 'Yes — but such sins carry no real consequence at all, since final salvation removes all divine displeasure.', 'No — remaining corruption was entirely and fully removed at their effectual calling, ruling out grievous sin.', 'Yes — through temptation and remaining corruption they may fall into grievous sins, incurring God’s displeasure for a time.'], answerIndex: 3 },
    'wcf-18-1': { q: 'According to WCF 18.1, may true believers be certainly assured of their state of grace in this life?', choices: ['Yes — those who truly believe, love Christ sincerely, and walk in good conscience may be certainly assured and rejoice in hope.', 'No — certainty of one’s own final salvation, even in this present life, is genuinely unattainable by anyone.', 'Yes — but only hypocrites and pretenders, and never any true believers, ever dare to claim such assurance.', 'No — such assurance belongs only to a rare few extraordinary saints, and not to believers generally at all.'], answerIndex: 0 },
    'wcf-18-2': { q: 'According to WCF 18.2, on what is the believer’s infallible assurance of grace founded?', choices: ['A bare probable persuasion, entirely without warrant, arrived at without any true testimony of the Spirit.', 'The divine promises, the evidence of grace to which they are made, and the Spirit’s testimony of adoption.', 'The believer’s outward church membership, regular activity, and mere participation in the sacraments.', 'A direct new revelation, given privately and secretly, entirely apart from any promise of Scripture itself.'], answerIndex: 1 },
  'wcf-18-3': { q: 'According to WCF 18.3, does infallible assurance so belong to the essence of faith that every believer has it at once?', choices: ['Yes — assurance is identical with saving faith itself, so every true believer has it immediately.', 'No — and it is not a believer’s duty to seek assurance at all, since it may breed pride.', 'No — a believer may wait long and struggle before attaining it, though it is his duty to make his calling sure.', 'Yes — but seeking such assurance tends to incline believers toward looseness of life.'], answerIndex: 2 },
    'wcf-18-4': { q: 'According to WCF 18.4, can a true believer’s assurance ever be shaken or diminished?', choices: ['No — once a believer attains assurance, it can never be shaken, diminished, or interrupted again.', 'Yes — and when shaken even slightly, the believer’s underlying faith and life are entirely extinguished.', 'No — assurance and saving faith are simply unrelated, so nothing shaking assurance ever touches faith.', 'Yes — by negligence, sin, or temptation it may be shaken or interrupted, yet the seed of God is never utterly lost.'], answerIndex: 3 },
  'wcf-19-1': { q: 'According to WCF 19.1, what kind of law did God give Adam as a covenant of works?', choices: ['A law binding him and his posterity to perfect, personal, perpetual obedience, with power given to keep it.', 'A law requiring only sincere, though imperfect, obedience, since perfection was never in view.', 'A law binding Adam alone, with no bearing at all on his posterity after him.', 'A law given without any power to keep it, so obedience was impossible from the start.'], answerIndex: 0 },
  'wcf-19-2': { q: 'According to WCF 19.2, how was the moral law delivered after the fall?', choices: ['As a rule since replaced entirely by the ceremonial laws given through Moses.', 'As a perfect rule of righteousness, given at Sinai in the Ten Commandments on two tables.', 'As a merely provisional rule, later abolished once the covenant of grace was revealed.', 'As ten separate commandments with no distinction between duty to God and to man.'], answerIndex: 1 },
  'wcf-19-3': { q: 'According to WCF 19.3, what is the status of the ceremonial laws given to Israel?', choices: ['They remain fully binding on the New Testament church alongside the moral law.', 'They were never truly typical of Christ, serving only Israel’s civil order.', 'They were typical ordinances prefiguring Christ, all now abrogated under the New Testament.', 'They were abrogated even before Christ came, ceasing already under the Old Testament.'], answerIndex: 2 },
    'wcf-19-4': { q: 'According to WCF 19.4, are Israel’s judicial laws still binding on other nations today?', choices: ['Yes — every judicial law given to Israel remains fully and equally binding on every modern nation.', 'No — they were never binding even on Israel itself, being merely advisory suggestions in character.', 'Yes — but only the penal sanctions, and not the underlying principles, still apply to modern nations.', 'No — they expired with the state of Israel, obliging others now only so far as their general equity may require.'], answerIndex: 3 },
  'wcf-19-5': { q: 'According to WCF 19.5, does Christ in the gospel dissolve the obligation of the moral law?', choices: ['No — the moral law forever binds all to obedience, and Christ in the gospel much strengthens this obligation.', 'Yes — Christ entirely dissolves the moral law’s obligation for all who believe in him.', 'Yes — the moral law binds only the unjustified, having no claim on believers at all.', 'No — but Christ neither strengthens nor weakens its obligation, leaving it exactly as before.'], answerIndex: 0 },
  'wcf-19-6a': { q: 'According to WCF 19.6, of what use is the moral law to believers, though they are not under it as a covenant of works?', choices: ['It has no use to believers at all, having been entirely set aside the moment they are justified.', 'As a rule of life it directs their duty, and by exposing remaining sin drives them to a clearer sight of their need of Christ.', 'It functions only as a covenant of works still, threatening believers with condemnation for every failure.', 'It serves merely as an ancient historical record, without any present directive force for believers.'], answerIndex: 1 },
  'wcf-19-6b': { q: 'According to WCF 19.6, does obeying the law because its promises encourage obedience prove a believer is under the law as a covenant of works?', choices: ['Yes — any obedience motivated by the law’s promises necessarily places a believer back under the covenant of works.', 'No — because the law’s promises and threatenings have no bearing whatsoever on believers under grace.', 'No — such obedience is no evidence of being under the law rather than under grace, even as the law also restrains corruption.', 'Yes — but this is acceptable, since believers are in fact still under the covenant of works today.'], answerIndex: 2 },
  'wcf-19-7': { q: 'According to WCF 19.7, do these uses of the law conflict with the grace of the gospel?', choices: ['Yes — the law’s uses are fundamentally contrary to grace, so gospel and law cannot coexist in the believer’s life.', 'No — though they do not truly comply with grace, God simply tolerates the two side by side.', 'Yes — grace nullifies every use of the law, leaving the believer with no rule of life at all.', 'No — they sweetly comply with grace, the Spirit of Christ enabling the will freely and cheerfully to do what the law requires.'], answerIndex: 3 },
  'wcf-20-1': { q: 'According to WCF 20.1, what does the Christian liberty purchased by Christ include?', choices: ['Freedom from the guilt of sin, condemning wrath, the curse of the law, and bondage to Satan, with free access to God.', 'Freedom from all civil and ecclesiastical authority, since Christ has released believers from every external rule.', 'Freedom from the moral law’s directive use, so believers are no longer bound to any of its commands.', 'Freedom limited to the ceremonial law only, with no bearing on guilt, wrath, or bondage to Satan.'], answerIndex: 0 },
  'wcf-20-2': { q: 'According to WCF 20.2, who alone is Lord of the conscience?', choices: ['The civil magistrate, whose laws bind the conscience in every matter of faith and worship.', 'God alone, who has left it free from doctrines and commandments of men contrary to or beside his Word.', 'Each believer’s own private judgment, unaccountable to any word of Scripture at all.', 'The visible church’s officers, whose commands bind the conscience even beside the Word.'], answerIndex: 1 },
    'wcf-20-3': { q: 'According to WCF 20.3, what happens to those who, under pretense of Christian liberty, practice sin or cherish lust?', choices: ['They rightly and fully exercise the whole extent of the liberty Christ purchased for every believer.', 'They commit no real error at all, since liberty by definition removes every kind of moral restraint.', 'They destroy the very end of Christian liberty, which is to serve the Lord without fear in holiness and righteousness.', 'They merely misuse a liberty that, in itself, actually has no true relation to holiness whatsoever.'], answerIndex: 2 },
  'wcf-20-4': { q: 'According to WCF 20.4, how does the Confession treat those who, under pretense of liberty, oppose lawful civil or church power?', choices: ['As faithfully exercising the very liberty that Christ died to purchase for his people.', 'As guilty of no wrong, since Christian liberty by nature overrides all civil and church authority.', 'As bound only by civil law, church authority having no claim on Christian liberty at all.', 'As resisting God’s ordinance, since lawful power and true liberty are meant to uphold one another.'], answerIndex: 3 },
    'wcf-21-1': { q: 'According to WCF 21.1, who determines the acceptable way to worship God?', choices: ['God himself, who has instituted and limited it by his own revealed will, not by men’s imaginations or devices.', 'The church, whose officers, synods, and councils may freely devise whatever forms seem edifying.', 'Each worshiper, individually and privately, according to whatever seems sincere and meaningful to him.', 'The civil magistrate, whose laws and decrees determine the forms acceptable within his own realm.'], answerIndex: 0 },
    'wcf-21-2': { q: 'According to WCF 21.2, to whom is religious worship to be given?', choices: ['To God, together with the angels, saints, and departed souls who intercede on our behalf.', 'To God alone — Father, Son, and Holy Ghost — and, since the fall, only through the mediation of Christ.', 'To Christ alone, apart from any worship at all directed to the Father or the Holy Ghost.', 'To whichever heavenly being, saint, or angel a worshiper finds most helpful as mediator.'], answerIndex: 1 },
  'wcf-21-3': { q: 'According to WCF 21.3, what is required for prayer to be acceptable to God?', choices: ['It must be offered through the intercession of departed saints who present it to God.', 'It may be offered in any tongue, whether known to the worshiper or not, so long as it is sincere.', 'It must be made in the Son’s name, by the Spirit’s help, according to God’s will, and if vocal, in a known tongue.', 'It requires no particular manner at all, since God accepts every prayer equally regardless of form.'], answerIndex: 2 },
  'wcf-21-4': { q: 'According to WCF 21.4, for whom is prayer not to be made?', choices: ['For any who are not yet believers, since prayer for unbelievers is never lawful.', 'For civil magistrates, since prayer is reserved only for fellow believers.', 'For oneself, since Christian prayer is properly directed only toward the needs of others.', 'For the dead, or for those known to have sinned the sin unto death.'], answerIndex: 3 },
  'wcf-21-5': { q: 'According to WCF 21.5, what are named as parts of the ordinary religious worship of God?', choices: ['The reading and preaching of Scripture, singing of psalms, and due administration of the sacraments.', 'Elaborate ceremony and images, which aid the worshiper’s devotion and understanding.', 'Silent meditation alone, without any reading, preaching, or singing being necessary.', 'The veneration of relics alongside the reading and preaching of the Word.'], answerIndex: 0 },
    'wcf-21-6': { q: 'According to WCF 21.6, is gospel worship tied to any particular place?', choices: ['Yes — under the gospel, in every place, acceptable worship is restricted to one consecrated site.', 'No — God is to be worshiped everywhere in spirit and truth, in private, in families, and in public assemblies.', 'No — but public assemblies, however important, may be neglected freely whenever God calls to them.', 'Yes — private worship, family worship, and personal devotion have been replaced by public assemblies.'], answerIndex: 1 },
    'wcf-21-7': { q: 'According to WCF 21.7, which day is now kept as the Christian Sabbath?', choices: ['The last day of the week, exactly as at creation, unchanged even after Christ’s own resurrection.', 'No single day at all, in particular, since the New Testament abolished weekly Sabbath observance.', 'The first day of the week, called the Lord’s Day, kept from Christ’s resurrection to the end of the world.', 'Whichever day of the week, in any given place, a congregation finds most convenient to observe.'], answerIndex: 2 },
  'wcf-21-8': { q: 'According to WCF 21.8, how is the Sabbath to be kept holy?', choices: ['By resting entirely from all activity, including even necessary works of mercy toward others.', 'By attending a single public service, after which the remainder of the day is free for ordinary business.', 'By abstaining from worship itself, the whole day being reserved only for physical rest.', 'By resting all day from worldly works and recreations, and being taken up in worship and duties of necessity and mercy.'], answerIndex: 3 },
    'wcf-22-1': { q: 'According to WCF 22.1, what is a lawful oath?', choices: ['A part of religious worship in which the swearer solemnly calls God to witness what he asserts or promises.', 'A purely civil formality, in every case, with no religious significance whatsoever attached.', 'A private promise made only to oneself, requiring no witness beyond one’s own conscience.', 'A vow made exclusively to another person, and never directly involving God in any way.'], answerIndex: 0 },
  'wcf-22-2': { q: 'According to WCF 22.2, by whose name alone is a person to swear an oath?', choices: ['Any sacred name or object the swearer personally finds meaningful, solemn, and fitting.', 'God’s name alone, and in weighty matters a lawful oath imposed by lawful authority ought to be taken.', 'God’s name is never to be used in an oath, since every oath of any kind is inherently sinful.', 'The name of a saint or angel, invoked as a fitting intermediary before God himself.'], answerIndex: 1 },
    'wcf-22-3': { q: 'According to WCF 22.3, what may a person lawfully bind himself to by an oath?', choices: ['Whatever another person demands of him, right or wrong, regardless of his own conviction.', 'Anything at all whatsoever, since an oath’s own solemnity alone makes any promise binding.', 'Only what is good and just, believed true, and able and resolved to be performed.', 'Only trivial matters of small import, since weighty commitments should never be sealed by oath.'], answerIndex: 2 },
    'wcf-22-4': { q: 'According to WCF 22.4, in what sense is an oath to be taken and kept?', choices: ['In whatever private sense the swearer alone intends, regardless of the words’ own plain meaning.', 'With mental reservation freely permitted, in any case, whenever keeping the oath proves too costly.', 'As void from the very start, in every single case, whenever it was made to an unbeliever or heretic.', 'In the plain, common sense of the words, binding to performance even to one’s own hurt, even when made to heretics.'], answerIndex: 3 },
    'wcf-22-5': { q: 'According to WCF 22.5, how does the Confession describe the nature of a vow?', choices: ['Of the same nature as a promissory oath, to be made and performed with like religious care and faithfulness.', 'Of an entirely different nature from an oath, requiring no real religious care in its making.', 'A merely private resolution of one’s own, carrying no binding obligation before God at all.', 'A civil contract only, in every respect, with no religious dimension distinguishing it from an oath.'], answerIndex: 0 },
    'wcf-22-6': { q: 'According to WCF 22.6, to whom is a vow to be made, and how?', choices: ['To a saint or angel, in Roman teaching, who then presents it before God on our behalf.', 'To God alone, voluntarily and out of faith and conscience of duty, in thankfulness or to obtain what is needed.', 'To the church, which then formally transmits the vow to God on the worshiper’s own behalf.', 'To oneself alone, since a vow properly binds the conscience without needing to be made to God.'], answerIndex: 1 },
    'wcf-22-7': { q: 'According to WCF 22.7, how does the Confession assess popish monastic vows of perpetual celibacy, poverty, and obedience?', choices: ['As a legitimate higher calling, in fact, commended for those able to keep such vows faithfully.', 'As lawful vows indeed, provided they are kept with the same care required of any other vow.', 'As no higher degree of perfection, but superstitious and sinful snares in which no Christian may entangle himself.', 'As matters of pure indifference, on the whole, neither commendable nor blameworthy in themselves.'], answerIndex: 2 },
    'wcf-23-1': { q: 'According to WCF 23.1, why has God ordained civil magistrates?', choices: ['Solely to protect the visible church’s own buildings, its property, and its institutional interests alone.', 'To administer the sacraments and to govern the internal, spiritual affairs of the whole church entirely.', 'To serve merely as an entirely honorary office, granted no real power at all to punish or defend anyone.', 'For his own glory and the public good, arming them with the power of the sword to defend the good and punish evildoers.'], answerIndex: 3 },
    'wcf-23-2': { q: 'According to WCF 23.2, may Christians lawfully hold the office of civil magistrate?', choices: ['Yes — they may lawfully accept and execute it, maintaining piety, justice, and peace, and may wage just and necessary war.', 'No — holding civil office is, in every possible sense, inherently incompatible with the Christian calling.', 'Yes — but only in offices that never require the use of force, coercion, or waging just war.', 'No — the New Testament restricts civil office, in every single case, to unbelievers governing the church.'], answerIndex: 0 },
    'wcf-23-3a': { q: 'According to WCF 23.3, may civil magistrates assume the ministry of the Word and sacraments?', choices: ['Yes — magistrates are given full authority over the ministry of Word, sacraments, and the keys.', 'No — but as nursing fathers they are to protect the church without preferring any one denomination above the rest.', 'No — and magistrates, in fact, have no duty whatsoever to protect the church in any way.', 'Yes — but only if they openly favor, in policy, a single established denomination over all others.'], answerIndex: 1 },
    'wcf-23-3b': { q: 'According to WCF 23.3, what is the magistrate’s duty toward people of differing religious views?', choices: ['To suppress by force any religious assembly, however different, that dissents from the established church.', 'To ignore entirely any indignity or violence, however severe, done to people for their religion.', 'To protect the person and good name of all their people, so none suffer indignity or violence for their religion or lack of it.', 'To protect only those who happen, by chance, to share the magistrate’s own religious convictions.'], answerIndex: 2 },
  'wcf-23-4': { q: 'According to WCF 23.4, does a difference in religion void a magistrate’s just and legal authority over his people?', choices: ['Yes — subjects owe obedience only to magistrates who share their own religious convictions.', 'No — but the pope retains authority to depose any magistrate of a different religion.', 'Yes — a magistrate of a different religion forfeits all claim to tribute and obedience.', 'No — and neither has the pope any power over magistrates or their people in their dominions.'], answerIndex: 3 },
    'wcf-24-1': { q: 'According to WCF 24.1, how many spouses may a person have at one time?', choices: ['Only one — no man may have more than one wife, nor any woman more than one husband, at the same time.', 'As many spouses as he is able, financially and practically, to provide for and treat justly.', 'Two spouses at most, provided the first wife or husband freely consents to the arrangement.', 'As many spouses as the civil law of a given nation happens to permit at any given time.'], answerIndex: 0 },
    'wcf-24-2': { q: 'According to WCF 24.2, for what purposes was marriage ordained?', choices: ['Solely for the legal transfer of property, inheritance, status, and title between two whole families.', 'For the mutual help of husband and wife, the increase of mankind and the church, and the prevention of uncleanness.', 'Solely for companionship and mutual lifelong friendship, with no purpose relating to children or sin.', 'Solely to provide the state with future citizens and taxpayers, apart from any moral purpose at all.'], answerIndex: 1 },
    'wcf-24-3': { q: 'According to WCF 24.3, whom should Christians marry?', choices: ['Whomever they choose, freely and without restriction, since Scripture places no limit on a believer’s spouse.', 'Only members of their own denomination, chapter, and confession, regardless of personal faith.', 'Only in the Lord, so they should not marry unbelievers, papists, idolaters, or others notoriously wicked or heretical.', 'Unbelievers, the irreligious, and the merely nominal, just as readily as true believers, provided it’s lawful.'], answerIndex: 2 },
  'wcf-24-4': { q: 'According to WCF 24.4, can an incestuous marriage, forbidden by the Word, ever be made lawful?', choices: ['Yes — human law may lawfully permit such marriages when both parties freely consent.', 'Yes — but only when neither party is aware of the forbidden degree of relationship.', 'No — though such marriages are lawful, they are simply inadvisable for practical reasons.', 'No — such marriages can never be made lawful by any human law or the consent of the parties.'], answerIndex: 3 },
    'wcf-24-5': { q: 'According to WCF 24.5, what may the innocent party do after adultery is committed by the other spouse after marriage?', choices: ['Sue for divorce and, after it, marry another as if the offending party were dead.', 'Nothing at all, in any case, since Scripture permits no divorce or remarriage whatsoever.', 'Only separate from bed and board, and forever, without any right to divorce or remarry.', 'Seek civil punishment of the offender, though the marriage bond, sadly, remains fully intact.'], answerIndex: 0 },
    'wcf-24-6': { q: 'According to WCF 24.6, what alone is sufficient cause to dissolve the marriage bond?', choices: ['Any serious, prolonged, and repeated disagreement between husband and wife over household matters.', 'Nothing but adultery or such willful desertion as cannot be remedied, pursued through a public, orderly course.', 'Either spouse’s own simple, private decision, without need of any public or orderly process.', 'Financial hardship alone, apart from any adultery or willful, irremediable desertion.'], answerIndex: 1 },
    'wcf-25-1': { q: 'According to WCF 25.1, what is the catholic or universal church, which is invisible?', choices: ['The whole number of baptized persons, professing and infant alike, throughout all of history.', 'The sum of all local congregations, in every place, presently gathered for public worship.', 'The whole number of the elect, gathered into one under Christ their Head, his spouse, body, and fullness.', 'A future assembly of the elect, gathered only after Christ’s return, at the final judgment.'], answerIndex: 2 },
    'wcf-25-2': { q: 'According to WCF 25.2, who makes up the visible church, and what is said of salvation outside it?', choices: ['Only those who can demonstrate certain, infallible assurance of their own election, without exception.', 'Only baptized infants alone, in every case, entirely apart from any adult profession of faith.', 'Anyone sincerely religious, of any faith at all, salvation being equally possible entirely outside it.', 'All who profess the true religion, with their children — outside of which there is no ordinary possibility of salvation.'], answerIndex: 3 },
    'wcf-25-3': { q: 'According to WCF 25.3, what has Christ given to the visible church for the gathering and perfecting of the saints?', choices: ['The ministry, oracles, and ordinances of God, made effectual by his own presence and Spirit.', 'Civil authority, and the power of the sword itself, to enforce true religion by force.', 'Only the ordinances, withholding entirely any ministry of the Word, from the visible church.', 'A guarantee, sealed and certain, that every professing member is truly among the elect.'], answerIndex: 0 },
    'wcf-25-4': { q: 'According to WCF 25.4, are particular churches equally pure at all times?', choices: ['Yes — every true particular church remains, in every single age, equally pure throughout its whole history.', 'No — they are more or less pure according as the gospel is taught, embraced, and worship performed more or less purely.', 'No — purity has nothing at all to do with, in any real respect, how the gospel or worship is conducted.', 'Yes — but only because purity depends, in every possible case, solely on unbroken apostolic succession.'], answerIndex: 1 },
    'wcf-25-5': { q: 'According to WCF 25.5, are even the purest churches on earth free from all error?', choices: ['Yes — the purest churches remain, in every single passing age, entirely and always free from error.', 'No — and for this very important reason, in fact, no true church remains on earth at any time.', 'No — the purest churches are subject to mixture and error, yet a church shall always remain on earth to worship God.', 'Yes — though lesser churches may err, in some considerable measure, the purest church is preserved.'], answerIndex: 2 },
    'wcf-25-6': { q: 'According to WCF 25.6, who is the head of the church, and who is denied that title?', choices: ['The pope of Rome, as Christ’s own vicar, rightly holds headship over the whole visible church.', 'Each national church has, in every land, its own head, distinct and independent of Christ.', 'The civil magistrate of each nation is, by law, head of the church within his own realm.', 'There is no other head but the Lord Jesus Christ; the pope of Rome can in no sense be head of the church.'], answerIndex: 3 },
    'wcf-26-1': { q: 'According to WCF 26.1, what fellowship do saints united to Christ share?', choices: ['Fellowship with him in his graces, sufferings, death, resurrection, and glory, and with one another in love.', 'Fellowship only in outward ordinances, with no inward sharing, in Christ’s graces or sufferings.', 'Fellowship confined, strictly and only, to members of one’s own local congregation alone.', 'Fellowship that ceases, entirely and immediately, the moment a believer departs this life.'], answerIndex: 0 },
  'wcf-26-2': { q: 'According to WCF 26.2, to whom may the communion of saints in outward things be extended?', choices: ['Only to members of one’s own particular denomination and no others.', 'As opportunity offers, to all who in every place call on the name of the Lord Jesus.', 'Only to those within one’s own local congregation, never beyond it.', 'Only to believers of the same nationality or civil jurisdiction as oneself.'], answerIndex: 1 },
    'wcf-26-3': { q: 'According to WCF 26.3, does communion with Christ make saints partakers of his Godhead?', choices: ['Yes — union with Christ makes believers, in some real sense, partakers of the divine essence.', 'No — but communion with Christ does, in effect, abolish each believer’s private property.', 'No — to affirm this is impious and blasphemous; nor does communion take away one’s title to his own goods.', 'Yes — and for this reason all goods, among true believers, ought to be held in common.'], answerIndex: 2 },
    'wcf-27-1': { q: 'According to WCF 27.1, what are sacraments?', choices: ['Merely symbolic ceremonies, with no real relation at all whatsoever, to the covenant of grace.', 'Human traditions, added to Scripture itself over time, to enrich the church’s corporate worship.', 'Means by which grace is, automatically and always and everywhere, conferred apart from any faith.', 'Holy signs and seals of the covenant of grace, instituted to represent Christ and engage us to his service.'], answerIndex: 3 },
    'wcf-27-2': { q: 'According to WCF 27.2, what relation exists between the sacramental sign and the thing signified?', choices: ['A spiritual relation, or sacramental union, so that the names and effects of the one are attributed to the other.', 'No relation at all, in any sense, the sign and the thing signified being entirely separate.', 'An identity, physical and actual, so that the sign is transformed into the thing signified.', 'A relation established, in every case, only by the private opinion of the individual receiving it.'], answerIndex: 0 },
    'wcf-27-3': { q: 'According to WCF 27.3, does the efficacy of a sacrament depend on the piety of the minister who administers it?', choices: ['Yes — an unworthy or impious minister renders the sacrament, in every single case, entirely void of grace.', 'No — grace is not conferred by any power in the sacrament, nor does efficacy depend on the piety of the administrator.', 'No — but efficacy does depend, at least in some very real part, on the intention of the administrator.', 'Yes — the sacrament’s power flows, in every single instance, from the personal holiness of the minister.'], answerIndex: 1 },
    'wcf-27-4': { q: 'According to WCF 27.4, how many sacraments did Christ ordain, and who may dispense them?', choices: ['Seven sacraments, following the tradition recognized widely, largely, throughout the Middle Ages.', 'Two sacraments, which any believer at all, in perfectly good standing, may lawfully dispense to any other.', 'Only two — baptism and the Lord’s Supper — neither of which may be dispensed except by a lawfully ordained minister.', 'Only one, the Lord’s Supper, baptism being merely, in this particular view, a ceremony and not a sacrament.'], answerIndex: 2 },
  'wcf-27-5': { q: 'According to WCF 27.5, how do the Old Testament sacraments compare to those of the New Testament?', choices: ['They signified an entirely different spiritual substance than the sacraments of the New Testament.', 'They were merely civil ceremonies, with no real spiritual substance signified at all.', 'They exhibited a lesser, incomplete grace not truly comparable to New Testament sacraments.', 'As to the spiritual things signified and exhibited, they were for substance the same as those of the New Testament.'], answerIndex: 3 },
    'wcf-28-1': { q: 'According to WCF 28.1, what does baptism signify and seal, beyond admission into the visible church?', choices: ['The covenant of grace, ingrafting into Christ, regeneration, remission of sins, and newness of life.', 'Nothing at all beyond outward admission, mere membership, into the visible church roll.', 'The believer’s own personal merit, publicly testified, before the whole congregation.', 'A civil rite of citizenship within the covenant community, without spiritual signification.'], answerIndex: 0 },
    'wcf-28-2': { q: 'According to WCF 28.2, in whose name is baptism administered, and by whom?', choices: ['In the name of the Father only, by any believer present, at the ceremony itself.', 'In the name of the Father, Son, and Holy Ghost, by a lawfully called minister of the gospel.', 'In the name of Christ only, by whichever elder happens, at the time, to be available.', 'In the name of the local congregation only, by its own elected representative.'], answerIndex: 1 },
  'wcf-28-3': { q: 'According to WCF 28.3, is dipping (immersion) necessary for baptism to be rightly administered?', choices: ['Yes — full immersion is the only mode by which baptism is validly administered.', 'No — but neither pouring nor sprinkling is valid; only aspersion by a priest suffices.', 'No — baptism is rightly administered by pouring or sprinkling water upon the person.', 'Yes — and any baptism by pouring or sprinkling must later be repeated by immersion.'], answerIndex: 2 },
  'wcf-28-4': { q: 'According to WCF 28.4, besides those who profess faith and obedience, who else is to be baptized?', choices: ['No one else — baptism under the New Testament is reserved strictly for professing adult believers.', 'Any infant whatsoever, whether or not either parent is a professing believer in the covenant.', 'Only infants whose grandparents, and not merely their parents, were professing believers.', 'The infants of one or both believing parents are also to be baptized, not professing believers only.'], answerIndex: 3 },
    'wcf-28-5': { q: 'According to WCF 28.5, is grace and salvation so tied to baptism that none can be saved without it?', choices: ['No — though neglecting the ordinance is a great sin, grace and salvation are not inseparably annexed to it.', 'Yes — without the outward administration of baptism itself, no person can ever be saved.', 'No — because baptism itself carries, in fact, no true spiritual significance at all.', 'Yes — and every single person, once baptized, is thereby undoubtedly and fully regenerated.'], answerIndex: 0 },
  'wcf-28-6': { q: 'According to WCF 28.6, is the efficacy of baptism tied to the very moment it is administered?', choices: ['Yes — the grace of baptism is conferred precisely and only at the moment water is applied.', 'No — the grace promised is really exhibited and conferred by the Holy Ghost according to God’s own appointed time.', 'No — because baptism, in fact, confers no grace at any time, before or after its administration.', 'Yes — but only for infants, adult baptism receiving grace at a separate, later time.'], answerIndex: 1 },
  'wcf-28-7': { q: 'According to WCF 28.7, how many times is the sacrament of baptism to be administered to any one person?', choices: ['As many times as the person later comes to a fuller, more mature profession of faith.', 'Twice in all — once in infancy and again upon a later, credible adult profession.', 'Only once — the sacrament of baptism is not to be repeated for any person.', 'Repeatedly, whenever assurance of its efficacy for that person seems to have been lost.'], answerIndex: 2 },
    'wcf-29-1': { q: 'According to WCF 29.1, why did Christ institute the Lord’s Supper?', choices: ['Solely as a social meal, commemorating warm and joyful fellowship among believers, without sealing benefits.', 'As a repeatable sacrifice, offered anew each single time, for the sins of both the living and the dead.', 'As a temporary ordinance, intended only for the very earliest apostolic generation, not for any other era.', 'For the perpetual remembrance of his sacrifice, the sealing of its benefits, spiritual nourishment, and a bond of communion.'], answerIndex: 3 },
    'wcf-29-2': { q: 'According to WCF 29.2, is Christ offered up to the Father again in the Lord’s Supper?', choices: ['No — it is only a commemoration of his one offering, so the popish sacrifice of the Mass is injurious to Christ’s one sacrifice.', 'Yes — Christ himself is truly and really re-offered up to the Father again, as a fresh sacrifice, each time.', 'No — but a lesser, spiritual sacrifice for sin is, nonetheless, still truly made at each and every observance.', 'Yes — though only invisibly, a genuine propitiatory sacrifice for sin, still truly occurs at every celebration.'], answerIndex: 0 },
  'wcf-29-3': { q: 'According to WCF 29.3, to whom is the sacrament to be given?', choices: ['To any person, present or absent, who requests it be brought to them.', 'To the communicants present in the congregation, not to any person not present.', 'To the minister alone, who then distributes its benefits by prayer on the people’s behalf.', 'To the whole community regardless of church membership, present or not.'], answerIndex: 1 },
  'wcf-29-4': { q: 'According to WCF 29.4, are private Masses, denying the cup to the people, and adoring the reserved elements in keeping with Christ’s institution?', choices: ['Yes — such practices reverently safeguard the sacrament’s dignity as Christ intended it.', 'No — but denying the cup alone is acceptable, the other practices being genuinely contrary.', 'No — all these are contrary to the nature of this sacrament and to Christ’s institution of it.', 'Yes — private Masses in particular were explicitly commanded in Christ’s own institution.'], answerIndex: 2 },
  'wcf-29-5': { q: 'According to WCF 29.5, what remains true of the bread and wine even though they are sometimes called by the names of Christ’s body and blood?', choices: ['In substance and nature they cease to be bread and wine altogether, becoming Christ’s actual body and blood.', 'They become a real mixture, part ordinary bread and wine and part the literal body and blood of Christ.', 'Their substance turns uncertain, changing to Christ’s body and blood only for those who receive them in true faith.', 'In substance and nature the bread and wine still remain truly and only bread and wine, despite the names applied to them.'], answerIndex: 3 },
    'wcf-29-6': { q: 'According to WCF 29.6, how does the Confession assess the doctrine of transubstantiation?', choices: ['As repugnant to Scripture and even common sense, overthrowing the sacrament’s nature and causing gross idolatries.', 'As a mystery beyond reason, yet fully and entirely consistent with Scripture and the sacrament’s nature.', 'As a legitimate development of doctrine, simply clarifying, what earlier ages left imprecise.', 'As a minor point of theological dispute, with no real bearing, on true or false worship at all.'], answerIndex: 0 },
    'wcf-29-7': { q: 'According to WCF 29.7, how do worthy receivers partake of Christ in the Lord’s Supper?', choices: ['Corporally and physically, in a crudely carnal and material way, Christ’s literal body and blood are chewed and swallowed.', 'Inwardly by faith they really receive Christ, not corporally, but as really and spiritually present as the elements are to their senses.', 'Only symbolically and by bare outward figure alone, with no real spiritual feeding upon Christ, ever occurring at all.', 'By a bare act of memory only, simply and merely recalling Christ’s death, without any true present feeding on him.'], answerIndex: 1 },
    'wcf-29-8': { q: 'According to WCF 29.8, what happens when ignorant and wicked men come to the Lord’s table?', choices: ['They receive the very same spiritual benefit as worthy receivers, since the sacrament works, apart from any faith.', 'They are automatically and entirely prevented from partaking at all, the elements being withheld always.', 'They receive the outward elements but not the thing signified, becoming guilty of the body and blood of the Lord to their own damnation.', 'They receive a somewhat lesser measure of the very same saving grace given to truly worthy receivers.'], answerIndex: 2 },
  'wcf-30-1': { q: 'According to WCF 30.1, in whose hands has Christ appointed a government for his church?', choices: ['In the hands of the civil magistrate, who governs the church alongside the state.', 'In the hands of no particular officers, each believer governing himself alone.', 'In the hands of a single universal bishop who rules the whole church.', 'In the hands of church officers, a government distinct from the civil magistrate.'], answerIndex: 3 },
  'wcf-30-2': { q: 'According to WCF 30.2, what power do church officers hold by the keys of the kingdom?', choices: ['Power to retain and remit sins, shutting the kingdom to the impenitent and opening it to penitent sinners.', 'Power to forgive sins entirely apart from any word of the gospel or censure of the church.', 'Power confined to teaching alone, with no authority to admit or exclude members.', 'Power delegated from the civil magistrate, exercised only with his approval.'], answerIndex: 0 },
    'wcf-30-3': { q: 'According to WCF 30.3, why are church censures necessary?', choices: ['Solely to punish offenders, having no aim, of reclaiming them or protecting the church.', 'For reclaiming offending brethren, deterring others, purging leaven, and vindicating Christ’s honor.', 'Only to protect the church’s public reputation, with no spiritual purpose, intended at all.', 'Only as a last resort, since Scripture, generally speaking, discourages church discipline.'], answerIndex: 1 },
    'wcf-30-4': { q: 'According to WCF 30.4, by what means are church officers to proceed in exercising censures?', choices: ['By civil fines, terms of imprisonment, and forced labor, imposed jointly with the magistrate.', 'By excommunication alone, without any lesser censures, such as admonition or suspension at all.', 'By admonition, suspension from the Lord’s Supper for a season, and excommunication, according to the offense.', 'By private rebuke only, the church having, in this view, no authority to suspend or excommunicate.'], answerIndex: 2 },
    'wcf-31-1': { q: 'According to WCF 31.1, who is to appoint and convene synods or councils, and how often?', choices: ['The civil magistrate alone, in every case, who alone determines when synods lawfully convene.', 'The pope alone, in Roman teaching, who possesses authority to summon a general council.', 'No one in particular at all — synods convene spontaneously, without any appointed authority.', 'The overseers and rulers of the churches, as often as they judge expedient for the good of the church.'], answerIndex: 3 },
    'wcf-31-2': { q: 'According to WCF 31.2, with what authority do the decrees of synods bind the conscience?', choices: ['Ministerially, so that decrees consonant with the Word are received with reverence, as an ordinance of God.', 'Infallibly, so that every decree of a lawfully convened synod binds the conscience absolutely.', 'Not at all — synod decrees carry, in fact, no more weight than any private opinion.', 'Civilly, and only civilly, binding insofar as the magistrate chooses to enforce them.'], answerIndex: 0 },
    'wcf-31-3': { q: 'According to WCF 31.3, can synods and councils since the apostles’ times err?', choices: ['No — every synod at all, without exception, since the apostles has been preserved from error.', 'Yes — they may err and many have erred, so they are not to be made the rule of faith or practice, but a help.', 'Yes — and for that reason, quite plainly and in fact, no synod’s decree should be received as any help.', 'No — only ecumenical councils indeed, and not particular synods, are preserved from all error.'], answerIndex: 1 },
    'wcf-31-4': { q: 'According to WCF 31.4, may synods and councils intermeddle with civil affairs of the commonwealth?', choices: ['Yes — synods hold full authority, in every case, to legislate on civil matters too.', 'No — synods may not even petition the magistrate, in any case, on any civil matter.', 'No — except by humble petition in extraordinary cases, or by advice when required by the civil magistrate.', 'Yes — but only in matters of taxation, and never in matters of civil law or justice at all.'], answerIndex: 2 },
    'wcf-32-1': { q: 'According to WCF 32.1, what happens to the souls of men immediately after death?', choices: ['They sleep in an unconscious state, entirely, awaiting reunion with the body at the resurrection.', 'They pass, for a time, through a temporary state of purification before entering heaven or hell.', 'They remain near their bodies on earth, in some sense, until summoned at the final judgment.', 'They immediately return to God — the righteous received into the highest heavens, the wicked cast into hell.'], answerIndex: 3 },
    'wcf-32-2': { q: 'According to WCF 32.2, what happens to the bodies of the dead at the last day?', choices: ['They shall be raised with the selfsame bodies, though with different qualities, united again to their souls forever.', 'They shall be raised with entirely new bodies, quite unrelated, to the bodies they had in this life.', 'They shall remain in the grave, forever and always, only the soul being raised to eternal life.', 'They shall be raised only for the righteous, in every case, the wicked receiving no resurrection.'], answerIndex: 0 },
    'wcf-32-3': { q: 'According to WCF 32.3, to what are the bodies of the just raised?', choices: ['To the very same dishonor, shame, and corruption that is appointed for the bodies of the unjust.', 'To honor, by the power of Christ’s Spirit, made conformable to his own glorious resurrection body.', 'To a purely spiritual existence, since no actual body at all is raised for the just.', 'To honor in outward appearance only, without any inward conformity to Christ’s own body.'], answerIndex: 1 },
    'wcf-33-1': { q: 'According to WCF 33.1, who will appear before Christ’s tribunal on the day of judgment?', choices: ['Only unbelievers, in absolutely every case, since believers already know their destiny and are exempt.', 'Only living human beings, in every single instance, since the dead have no part in final judgment.', 'The apostate angels and all persons who ever lived, to give account and receive according to what they have done.', 'Only those persons still living, at Christ’s own actual return, the dead being excluded entirely.'], answerIndex: 2 },
  'wcf-33-2': { q: 'According to WCF 33.2, what is the twofold end of appointing the day of judgment?', choices: ['The manifestation of God’s justice alone, mercy having no place in the final judgment.', 'The manifestation of God’s mercy alone, since even the wicked will finally be shown mercy.', 'The demonstration of human free will, apart from any manifestation of God’s own attributes.', 'The manifestation of God’s mercy in the elect’s salvation and of his justice in the reprobate’s damnation.'], answerIndex: 3 },
    'wcf-33-3': { q: 'According to WCF 33.3, why has Christ left the exact day of judgment unknown?', choices: ['So that men may shake off carnal security, be ever watchful, and always ready to say, Come, Lord Jesus, come quickly.', 'So that no one, in any case, would ever need to prepare, watch, or be ready for it at all.', 'So that only especially devout, mature, and discerning believers could discern its signs.', 'So that civil magistrates alone, and not the church, would bear responsibility for final preparation.'], answerIndex: 0 },
  };
  global.PCA_CARD_QUIZ = Object.assign(global.PCA_CARD_QUIZ || {}, Q);
})(typeof window !== 'undefined' ? window : globalThis);
